import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.B9unkguw.js";const u=JSON.parse('{"title":"Vehicle Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"tr/qgc-user-guide/setup_view/setup_view.md","filePath":"tr/qgc-user-guide/setup_view/setup_view.md"}'),i={name:"tr/qgc-user-guide/setup_view/setup_view.md"};function s(n,e,h,l,c,f){return t(),r("div",null,e[0]||(e[0]=[o('<h1 id="vehicle-configuration" tabindex="-1">Vehicle Configuration <a class="header-anchor" href="#vehicle-configuration" aria-label="Permalink to &quot;Vehicle Configuration&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Having trouble?</p><p>If QGC won&#39;t connect to your vehicle, see <a href="./../troubleshooting/vehicle_connection.html">Connection Problems</a>. If parameters fail to load, see <a href="./../troubleshooting/parameter_download.html">Parameter Download Failures</a>.</p></div><p>The Vehicle Configuration view is used to configure a new vehicle prior to first flight and/or tune a configured vehicle.</p><h2 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to &quot;Search&quot;">​</a></h2><p>Use the <strong>search bar</strong> at the top of the configuration sidebar to find any setting by name. As you type, matching settings are shown across all pages — click a result to jump directly to that setting.</p><h2 id="configuration-pages" tabindex="-1">Configuration Pages <a class="header-anchor" href="#configuration-pages" aria-label="Permalink to &quot;Configuration Pages&quot;">​</a></h2><p>To the left of the screen are the available configuration pages. A page is marked with a red icon if there are still settings needed to be adjusted/specified. You should not fly if any of these are red.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>The set of pages shown and the contents of each page may differ based on whether the vehicle is running PX4 or ArduPilot firmware.</p></div><p><strong>Summary</strong> <br>An overview of all the important configuration options for your vehicle. Summary blocks show a red indicator when settings are not fully configured.</p><p><strong>PX4-specific pages:</strong> <a href="./px4/actuators.html">Actuators / Motors</a>, <a href="./airframe_px4.html">Airframe</a>, <a href="./flight_modes_px4.html">Flight Modes</a>, <a href="./tuning_px4.html">PID Tuning</a>, <a href="./power.html">Power</a>, <a href="./radio.html">Radio</a>, <a href="./safety.html">Safety</a>, <a href="./sensors_px4.html">Sensors</a></p><p><strong>ArduPilot-specific pages:</strong> <a href="./ardupilot/esc.html">ESC</a>, <a href="./ardupilot/failsafes.html">Failsafes</a>, <a href="./flight_modes_ardupilot.html">Flight Modes</a>, <a href="./ardupilot/flight_safety.html">Flight Safety</a>, <a href="./airframe_ardupilot.html">Frame</a>, <a href="./camera.html">Gimbal</a>, <a href="./logging_ardupilot.html">Logging</a>, <a href="./motors.html">Motors</a>, <a href="./power.html">Power</a>, <a href="./radio.html">Radio</a>, <a href="./ardupilot/remote_support.html">Remote Support</a>, <a href="./ardupilot/scripting.html">Scripting</a>, <a href="./sensors_ardupilot.html">Sensors</a>, <a href="./ardupilot/servo_outputs.html">Servo Outputs</a>, <a href="./tuning_ardupilot.html">Tuning</a>, <a href="./ardupilot/vehicle_specific.html">Vehicle-Specific</a></p><p><strong>Shared pages:</strong></p><p><strong><a href="./joystick.html">Joystick</a></strong> <br>Configure a joystick or gamepad for vehicle control.</p><p><strong><a href="./firmware.html">Firmware</a></strong> <br>Flash new firmware onto the flight controller.</p><p><strong><a href="./parameters.html">Parameters</a></strong> <br>View and modify all parameters associated with your vehicle.</p>',15)]))}const g=a(i,[["render",s]]);export{u as __pageData,g as default};
